   249→ *      // With Content-Type: text/html; charset=utf-8
   250→ *      req.is('html');
   251→ *      req.is('text/html');
   252→ *      req.is('text/*');
   253→ *      // => true
   254→ *
   255→ *      // When Content-Type is application/json
   256→ *      req.is('json');
   257→ *      req.is('application/json');
   258→ *      req.is('application/*');
   259→ *      // => true
   260→ *
   261→ *      req.is('html');
   262→ *      // => false
   263→ *
   264→ * @param {String|Array} types...
   265→ * @return {String|false|null}
   266→ * @public
