   332→ *
   333→ * The is the remote address on the socket unless
   334→ * "trust proxy" is set.
   335→ *
   336→ * @return {String}
   337→ * @public
   338→ */
   339→
   340→defineGetter(req, 'ip', function ip(){
   341→  var trust = this.app.get('trust proxy fn');
   342→  return proxyaddr(this, trust);
   343→});
