   362→  // and remove socket address
   363→  addrs.reverse().pop()
   364→
   365→  return addrs
   366→});
   367→
   368→/**
   369→ * Return subdomains as an array.
   370→ *
   371→ * Subdomains are the dot-separated parts of the host before the main domain of
   372→ * the app. By default, the domain of the app is assumed to be the last two
   373→ * parts of the host. This can be changed by setting "subdomain offset".
   374→ *
   375→ * For example, if the domain is "tobi.ferrets.example.com":
   376→ * If "subdomain offset" is not set, req.subdomains is `["ferrets", "tobi"]`.
   377→ * If "subdomain offset" is 3, req.subdomains is `["tobi"]`.
   378→ *
   379→ * @return {Array}
   380→ * @public
   381→ */
   382→
   383→defineGetter(req, 'subdomains', function subdomains() {
   384→  var hostname = this.hostname;
   385→
   386→  if (!hostname) return [];
   387→
