   490→ * "Last-Modified" and / or the "ETag" for the
   491→ * resource has changed.
   492→ *
   493→ * @return {Boolean}
   494→ * @public
   495→ */
   496→
   497→defineGetter(req, 'stale', function stale(){
   498→  return !this.fresh;
   499→});
   500→
   501→/**
   502→ * Check if the request was an _XMLHttpRequest_.
   503→ *
   504→ * @return {Boolean}
   505→ * @public
   506→ */
